import sys

def main():
    import sys
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    M = int(data[1])
    L = list(map(int, data[2:]))

    def is_possible(W):
        lines = 1
        current_width = 0
        for word in L:
            if current_width + word + (1 if current_width > 0 else 0) <= W:
                current_width += word + (1 if current_width > 0 else 0)
            else:
                lines += 1
                current_width = word
                if lines > M:
                    return False
        return True

    left = max(L)
    right = sum(L) + (N - 1)
    answer = right

    while left <= right:
        mid = (left + right) // 2
        if is_possible(mid):
            answer = mid
            right = mid - 1
        else:
            left = mid + 1

    print(answer)

if __name__ == "__main__":
    main()
